# 

# [+,1,1,1,1,""]            0+1=1
# [+,2,3,2,2,""]            1+2=3
# [.,3,24,23,23,s]          3-2+2.3    =24       | s[1][2]-s[1][1]+(s[1][1]+s[2][1])
# [*,4,93,92,4,""]          24-23+23*4=93   | 
# [.,5,1036,1035,45,*]      93-92+92/4*4.5    =1036
# [.,6,10489,10488,456,*]   1036-1035+1035/45*45.6=10489
# [*,7,73417,73416,7,""]    10489-10488+10488*7=73417
# [+,8,73425,8,8,""]        73417+8=73425

debug = False

class Solution:
    def addOperators(self, num: str, target: int) -> List[str]:
        num_it = 0

        # [0: status(str) f, 1: cur_single_num(str) f, 2: total(int) f, 3: to_remove(int), 4: new_full_num(str) f, 5: last_status(str) f]
        stack = []

        outputs = []
        status_full = ["+","+",".","*",".",".","*","+"]
        status = ["+"]
        tried = []

        # status_it=0
        while True:
            # status.append(status_full[status_it])
            # if len(to_append)<len(status):
            stack.append([status[-1],num[num_it],0,0,"",""])
            

            if len(stack)>1:
                stack[-1][2]=stack[-2][2]
                
            if stack[-1][0]==".":
                # if stack[-2][0]!=".":
                #     stack[-1][5]=stack[-2][0]
                # else:
                stack[-1][5]=stack[-2][5]
                
                # cur total subtracted
                # stack[-1][2]=stack[-2][2]-stack[-2][3]

                # new dot/num
                stack[-1][4] = stack[-2][4]+num[num_it]

                # dot_mult_div = stack[-2][3]//int(stack[-2][4])
            else:
                stack[-1][4]=stack[-1][1]
                stack[-1][5]=stack[-1][0]

            if debug:
                print(len(stack))
                print("first: ", stack[-1])
            
            if stack[-1][0]=="*" or stack[-1][0]==".":
                stack[-1][2]-=stack[-2][3]

            if debug:
                print("second: ", stack[-1])


            if stack[-1][5]=="+" or stack[-1][5]=="-":
                cur_num = int(stack[-1][5]+stack[-1][4])
                stack[-1][2]+=cur_num
                stack[-1][3]=cur_num
            

            elif stack[-1][5]=="*":
                cur_num = int(stack[-1][4])
                stack[-1][3]=stack[-2][3]
                if stack[-1][0]==".":
                    stack[-1][3]=stack[-1][3]//int(stack[-2][4])
                stack[-1][3]*=cur_num
                stack[-1][2]+=stack[-1][3]
            
            if debug:
                print("third: ", stack[-1])
            
            num_it+=1

            if len(tried)<num_it:
                tried.append(set())
            
            if len(tried)!=0 and len(tried[-1])==4:
                print("tried full too early")
                raise
            tried[-1].add(status[-1])
            
            if debug:
                print(len(tried), tried[-1])
                print("--------------")

            if len(stack)==len(num):
                if stack[-1][2] == target:
                    good_string = []
                    for s in stack:
                        if s[0]!=".":
                            good_string.append(s[0])
                        good_string.append(s[1])
                    
                    outputs.append("".join(good_string[1:]))
                
                status.pop()
                num_it-=1
                stack.pop()
                while True:
                    if len(tried)==1:
                        print("finished")
                        return outputs
                    # if stack[-1][1]!="0" and len(tried[-1])!=4:
                    #     break
                    if stack[-1][1]=="0" and stack[-1][0]!=".":
                        limit = 3
                    else:
                        limit = 4
                    if len(tried[-1]) < limit:
                        break
                    tried.pop()
                    status.pop()
                    num_it-=1
                    stack.pop()
            
            if len(status)<len(tried):
                allowed_set = {".","*","-","+"}
                if stack[-1][1]=="0" and stack[-1][0]!=".":
                    allowed_set.remove(".")
                # print("allowed:", allowed_set - tried[-1])
                status.append(next(iter(allowed_set - tried[-1])))
            else:
                status.append("+")
            
            # num_it+=1
            # status_it+=1
            # if status_it == len(status_full):
            #     break
        
        return outputs


